<?php include 'app/views/layouts/header.php'; ?><h2 class='fw-bold'>📌 Program Data Entry</h2><p class='text-muted'>Umbrella program information from the Extension Office.</p><?php if($message): ?><div class='alert alert-info'><?= $message ?></div><?php endif; ?><div class='card p-4 mb-4'><form method='POST'><div class='row g-3'><div class='col-md-6'><label>Program Title</label><input name='program_title' class='form-control' required></div><div class='col-md-3'><label>Program Cost</label><input type='number' step='0.01' name='project_cost' class='form-control'></div><div class='col-md-3'><label>Special Order No.</label><input name='special_order_no' class='form-control'></div><div class='col-md-4'><label>Leader</label><input name='leader' class='form-control'></div><div class='col-md-4'><label>Assistant Leader</label><input name='assistant_leader' class='form-control'></div><div class='col-md-4'><label>Members</label><textarea name='members' class='form-control'></textarea></div><div class='col-md-3'><label>Start Date</label><input type='date' name='start_date' class='form-control'></div><div class='col-md-3'><label>End Date</label><input type='date' name='end_date' class='form-control'></div><div class='col-12'><button class='btn btn-primary'>Save Program</button></div></div></form></div><div class='card p-3'><table class='table table-hover'><thead><tr><th>Program</th><th>Leader</th><th>Assistant</th><th>Cost</th><th>Duration</th><th>S.O.</th></tr></thead><tbody><?php foreach($programs as $p): ?><tr><td><?= htmlspecialchars($p['program_title']) ?></td><td><?= htmlspecialchars($p['leader']) ?></td><td><?= htmlspecialchars($p['assistant_leader']) ?></td><td>₱<?= number_format($p['project_cost'],2) ?></td><td><?= $p['start_date'] ?> to <?= $p['end_date'] ?></td><td><?= htmlspecialchars($p['special_order_no']) ?></td></tr><?php endforeach; ?></tbody></table></div><?php include 'app/views/layouts/footer.php'; ?>
